solution_code:
#include <iostream>

class ID
{
    int m_id{};
public:
    ID(int id) : m_id{ id } {}

    explicit operator bool() const
    {
        return m_id > 0;
    }
};

int main()
{
    int n{};
    std::cin >> n;

    for (int i{ 0 }; i < n; ++i)
    {
        int val{};
        std::cin >> val;
        ID id{ val };

        if (id)
            std::cout << "valid\n";
        else
            std::cout << "invalid\n";
    }

    return 0;
}
